const e=JSON.parse('{"key":"v-4839356e","path":"/learningNote/Computer_Network/TCP%E4%B8%8EUDP%E4%B8%8E%E4%BB%96%E4%BB%AC%E7%9A%84%E5%85%B3%E7%B3%BB.html","title":"TCP与UDP与他们之间的关系","lang":"zh-CN","frontmatter":{"title":"TCP与UDP与他们之间的关系","category":["Computer","Network","basic"]},"headers":[{"level":2,"title":"UDP","slug":"udp","link":"#udp","children":[]}],"git":{"createdTime":1699194743000,"updatedTime":1699252784000,"contributors":[{"name":"Jeacson_Snake","email":"Jeacson_Snake@outlook.com","commits":2}]},"readingTime":{"minutes":2.59,"words":777},"filePathRelative":"learningNote/Computer_Network/TCP与UDP与他们的关系.md","localizedDate":"2023年11月5日","excerpt":"<h2> UDP</h2>\\n<p>UDP 是一种简洁、轻量级的传输协议，只提供最基本的通讯服务。UDP 定义于 [RFC 768]，其功能与传输协议差不多。除了多路复用/解复用功能和一些轻微的错误检查功能外，它没有为 IP 增加任何功能。也就是说，如果一个应用程序开发人员选择 UDP 而不是 TCP 作为传输协议的话，那么该应用程序几乎可以被认为是在直接与 IP 对话而没有任何其他的包装。</p>\\n<p>UDP 是无连接的，因此在两个进程开始通信之前不需要提前握手。因此，当应用程序通过 UDP 而不是 TCP 运行时，专用于这些特定应用程序的服务器通常可以支持更多的在线客户端。</p>\\n<p>UDP 提供的是一种不可靠的数据传输服务，也就是说：</p>"}');export{e as data};
